using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

// Lightweight fake — no mocking framework needed.
internal sealed class FakePaymentProvider : IPaymentProvider
{
    public ChargeResult? ChargeResultToReturn { get; set; }
    public RefundResult? RefundResultToReturn { get; set; }
    public Exception? ExceptionToThrow { get; set; }

    // Captured arguments for verification
    public string? LastCardToken { get; private set; }
    public decimal LastAmount { get; private set; }
    public string? LastChargeId { get; private set; }

    public Task<ChargeResult> ChargeAsync(string cardToken, decimal amount)
    {
        LastCardToken = cardToken;
        LastAmount = amount;

        if (ExceptionToThrow is not null) throw ExceptionToThrow;
        return Task.FromResult(ChargeResultToReturn!);
    }

    public Task<RefundResult> RefundAsync(string chargeId)
    {
        LastChargeId = chargeId;

        if (ExceptionToThrow is not null) throw ExceptionToThrow;
        return Task.FromResult(RefundResultToReturn!);
    }
}

[TestClass]
public class PaymentGatewayConstructorTests
{
    [TestMethod]
    public void Constructor_NullProvider_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => new PaymentGateway(null!));
    }
}

[TestClass]
public class ChargeAsyncTests
{
    private FakePaymentProvider _provider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _provider = new FakePaymentProvider
        {
            ChargeResultToReturn = new ChargeResult("ch_123", true)
        };
        _gateway = new PaymentGateway(_provider);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.AreEqual("ch_123", result.ChargeId);
    }

    [TestMethod]
    public async Task ChargeAsync_ValidInput_ForwardsArgumentsToProvider()
    {
        await _gateway.ChargeAsync("tok_abc", 100m);

        Assert.AreEqual("tok_abc", _provider.LastCardToken);
        Assert.AreEqual(100m, _provider.LastAmount);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task ChargeAsync_InvalidCardToken_ThrowsArgumentException(string? token)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.ChargeAsync(token!, 10m));
    }

    [TestMethod]
    [DataRow(0)]
    [DataRow(-1)]
    [DataRow(-0.01)]
    public async Task ChargeAsync_NonPositiveAmount_ThrowsArgumentOutOfRangeException(double amount)
    {
        await Assert.ThrowsExceptionAsync<ArgumentOutOfRangeException>(
            () => _gateway.ChargeAsync("tok_valid", (decimal)amount));
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderFails_ReturnsFalseResult()
    {
        _provider.ChargeResultToReturn = new ChargeResult("ch_fail", false);

        var result = await _gateway.ChargeAsync("tok_valid", 10m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_ProviderThrows_ExceptionPropagates()
    {
        _provider.ExceptionToThrow = new InvalidOperationException("gateway down");

        await Assert.ThrowsExceptionAsync<InvalidOperationException>(
            () => _gateway.ChargeAsync("tok_valid", 10m));
    }
}

[TestClass]
public class RefundAsyncTests
{
    private FakePaymentProvider _provider = null!;
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _provider = new FakePaymentProvider
        {
            RefundResultToReturn = new RefundResult("rf_456", true)
        };
        _gateway = new PaymentGateway(_provider);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccess()
    {
        var result = await _gateway.RefundAsync("ch_123");

        Assert.IsTrue(result.Success);
        Assert.AreEqual("rf_456", result.RefundId);
    }

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ForwardsToProvider()
    {
        await _gateway.RefundAsync("ch_xyz");

        Assert.AreEqual("ch_xyz", _provider.LastChargeId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public async Task RefundAsync_InvalidChargeId_ThrowsArgumentException(string? chargeId)
    {
        await Assert.ThrowsExceptionAsync<ArgumentException>(
            () => _gateway.RefundAsync(chargeId!));
    }

    [TestMethod]
    public async Task RefundAsync_ProviderFails_ReturnsFalseResult()
    {
        _provider.RefundResultToReturn = new RefundResult("rf_fail", false);

        var result = await _gateway.RefundAsync("ch_123");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task RefundAsync_ProviderThrows_ExceptionPropagates()
    {
        _provider.ExceptionToThrow = new TimeoutException("timed out");

        await Assert.ThrowsExceptionAsync<TimeoutException>(
            () => _gateway.RefundAsync("ch_123"));
    }
}

[TestClass]
public class ProcessWebhookTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway(new FakePaymentProvider());
    }

    [TestMethod]
    public void ProcessWebhook_ValidPayload_ReturnsWebhookEvent()
    {
        var payload = """{"type":"charge.succeeded","resourceId":"ch_123"}""";

        var evt = _gateway.ProcessWebhook(payload);

        Assert.AreEqual("charge.succeeded", evt.EventType);
        Assert.AreEqual("ch_123", evt.ResourceId);
    }

    [TestMethod]
    public void ProcessWebhook_RefundEvent_ReturnsCorrectType()
    {
        var payload = """{"type":"refund.created","resourceId":"rf_456"}""";

        var evt = _gateway.ProcessWebhook(payload);

        Assert.AreEqual("refund.created", evt.EventType);
        Assert.AreEqual("rf_456", evt.ResourceId);
    }

    [TestMethod]
    [DataRow(null)]
    [DataRow("")]
    [DataRow("   ")]
    public void ProcessWebhook_EmptyPayload_ThrowsArgumentException(string? payload)
    {
        Assert.ThrowsException<ArgumentException>(
            () => _gateway.ProcessWebhook(payload!));
    }

    [TestMethod]
    public void ProcessWebhook_InvalidJson_ThrowsFormatException()
    {
        Assert.ThrowsException<FormatException>(
            () => _gateway.ProcessWebhook("not json"));
    }

    [TestMethod]
    public void ProcessWebhook_MissingType_ThrowsFormatException()
    {
        var payload = """{"resourceId":"ch_123"}""";

        Assert.ThrowsException<FormatException>(
            () => _gateway.ProcessWebhook(payload));
    }

    [TestMethod]
    public void ProcessWebhook_MissingResourceId_ThrowsFormatException()
    {
        var payload = """{"type":"charge.succeeded"}""";

        Assert.ThrowsException<FormatException>(
            () => _gateway.ProcessWebhook(payload));
    }

    [TestMethod]
    public void ProcessWebhook_ExtraFieldsIgnored_StillParses()
    {
        var payload = """{"type":"charge.succeeded","resourceId":"ch_1","extra":"ignored"}""";

        var evt = _gateway.ProcessWebhook(payload);

        Assert.AreEqual("charge.succeeded", evt.EventType);
    }
}

